import React from 'react';
import { useLocation } from 'react-router-dom';

export function MyTrip() {
  const location = useLocation();
  const tripResult = location.state?.tripResult; // Accessing tripResult from the state passed

  console.log("Trip result:", tripResult);

  return (
    <div className="py-8 w-11/12 mx-auto text-white bg-gray-800 rounded-lg shadow-md">
      <div className='flex flex-col items-center justify-center'>
        {/* Render trip details */}
        <h1 className="text-3xl font-bold mb-4">{tripResult.trip_name}</h1>
       </div>
    </div>
  );
}
